#include <stdio.h>
#include <sys/time.h>
#include <float.h>
#include <math.h>
#include <stdlib.h>
#include <string.h>
#include <omp.h>

#ifdef TIMING
#include "timing.h"

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#define min( a, b )			a > b ? b : a
#define ceilDiv( a, b )		( a + b - 1 ) / b
#define print( x )			printf( #x ": %lu\n", (unsigned long) x )
#define DEBUG				false

#define DEFAULT_THREADS_PER_BLOCK 256

#define MAX_ARGS 10
#define REC_LENGTH 53 
#define LATITUDE_POS 28	
#define OPEN 10000	

#define MAX_RECORDS 1000000

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

int loadData(char *filename, Record *records, LatLong *locations, int maxRecords);
void findLowest(Record *records, float *distances, int numRecords, int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

void euclid_openmp(LatLong *d_locations, float *d_distances, int numRecords, float lat, float lng)
{
    #pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; ++globalId) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        *dist = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) + (lng - latLong->lng) * (lng - latLong->lng));
    }
}

int main(int argc, char* argv[])
{
	int    i=0;
	float lat, lng;
	int quiet=0,timing=0,platform=0,device=0;

    Record *records = (Record *)malloc(sizeof(Record) * MAX_RECORDS);
    LatLong *locations = (LatLong *)malloc(sizeof(LatLong) * MAX_RECORDS);
    char filename[100];
    int resultsCount=10;

    if (!records || !locations) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      free(records);
      free(locations);
      return 0;
    }

    int numRecords = loadData(filename, records, locations, MAX_RECORDS);
    if (resultsCount > numRecords) resultsCount = numRecords;

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    LatLong *d_locations = (LatLong *)malloc(sizeof(LatLong) * numRecords);
    float *d_distances = (float *)malloc(sizeof(float) * numRecords);

    if (!distances || !d_locations || !d_distances) {
        fprintf(stderr, "Memory allocation failed\n");
        free(records);
        free(locations);
        return 1;
    }

    unsigned long threadsPerBlock = DEFAULT_THREADS_PER_BLOCK;
    unsigned long blocks = ceilDiv( numRecords, threadsPerBlock ); 
    unsigned long maxGridX = 65535;
    unsigned long gridY = ceilDiv( blocks, maxGridX );
    unsigned long gridX = ceilDiv( blocks, gridY );

    if ( DEBUG )
    {
        print( maxGridX ); 
        print( threadsPerBlock );
        print( blocks ); 
        print( gridY );
        print( gridX );
    }

    memcpy(d_locations, locations, sizeof(LatLong) * numRecords);

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    euclid_openmp(d_locations, d_distances, numRecords, lat, lng);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    memcpy(distances, d_distances, sizeof(float)*numRecords);

    findLowest(records, distances, numRecords, resultsCount);

    if (!quiet) {
        for(i=0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }
    }

    free(distances);
    free(d_locations);
    free(d_distances);
    free(records);
    free(locations);

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif

    return 0;
}

int loadData(char *filename, Record *records, LatLong *locations, int maxRecords){
    FILE   *flist, *fp;
	int    i=0;
	char dbname[64];
	int recNum=0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist: %s\n", filename);
        exit(0);
    }

    while(!feof(flist) && recNum < maxRecords) {
        if(fscanf(flist, "%s\n", dbname) != 1) {
            if (!feof(flist)) {
                fprintf(stderr, "error reading filelist\n");
                exit(0);
            }
            break;
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db: %s\n", dbname);
            exit(1);
        }

        while(!feof(fp) && recNum < maxRecords){
            Record *record = &records[recNum];
            LatLong *latLong = &locations[recNum];

            if (fgets(record->recString, 49, fp) == NULL) break;
            int ch = fgetc(fp); 

            char substr[6];

            for(i=0; i < 5; i++) {
                int idx = i + 28;
                if (idx < 49 && record->recString[idx] != '\0')
                    substr[i] = record->recString[idx];
                else 
                    substr[i] = ' ';
            }
            substr[5] = '\0';
            latLong->lat = atof(substr);

            for(i=0; i < 5; i++) {
                int idx = i + 33;
                if (idx < 49 && record->recString[idx] != '\0')
                    substr[i] = record->recString[idx];
                else 
                    substr[i] = ' ';
            }
            substr[5] = '\0';
            latLong->lng = atof(substr);

            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN){
  int i, j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for(i=0; i < topN; i++) {
    minLoc = i;
    for(j=i; j < numRecords; j++) {
      val = distances[j];
      if (distances[minLoc] > val) minLoc = j;
    }

    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (argc < 2) return 1; 
    strncpy(filename, argv[1], 100);
    char flag;

    *r = 10;
    *lat = 0.0;
    *lng = 0.0;
    *q = 0;
    *t = 0;
    *p = -1;
    *d = -1;

    for(i=1; i < argc; i++) {
      if ('-' == argv[i][0]) {
        flag = argv[i][1];
        switch (flag) {
            case 'r': 
              i++;
              if (i < argc) *r = atoi(argv[i]);
              break;
            case 'l': 
              if (i+1 < argc) {
                if ('a' == argv[i][2]) {
                  *lat = atof(argv[i+1]);
                }
                else {
                  *lng = atof(argv[i+1]);
                }
                i++;
              }
              break;
            case 'h': 
              return 1;
            case 'q': 
              *q = 1;
              break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              i++;
              if (i < argc) *p = atoi(argv[i]);
              break;
            case 'd': 
              i++;
              if (i < argc) *d = atoi(argv[i]);
              break;
        }
      }
    }
    if ((0 <= *d && *p < 0) || (0 <= *p && 0 > *d)) 
      return 1;
    return 0;
}

